const i=[{key:"passport",title:"Get a valid passport",description:"Your passport must be valid for at least 6 more months on the day you leave. If it expires sooner, renew now — the queue at Nyayo House gets long every Kenyan holiday season.",proTip:"Use the eCitizen portal to book your appointment online instead of walking in.",estimatedDuration:"1–3 weeks",category:"documents",ctaLink:"/services",ctaLabel:"Need help applying?"},{key:"kcse_attestation",title:"Attest your KCSE / academic certificates",description:"Most overseas employers (especially in the Gulf) require KCSE + any college certs attested by the Kenya National Examinations Council (KNEC), then by the Ministry of Foreign Affairs (MoFA), then by the destination country's embassy.",proTip:"Start this BEFORE you sign any contract — the full chain takes 4–8 weeks.",estimatedDuration:"4–8 weeks",category:"documents"},{key:"good_conduct",title:"Get a Certificate of Good Conduct",description:"DCI Police Clearance Certificate. Required for almost every overseas work visa. Apply via eCitizen — takes 10–14 days.",proTip:"It's valid for 6 months. If your departure date is far off, time it carefully.",estimatedDuration:"10–14 days",category:"documents"},{key:"cv_ready",title:"Build an ATS-ready CV",description:"An ATS (Applicant Tracking System) CV is what overseas employers use to filter candidates. Fancy fonts and graphics get auto-rejected. Plain layout, keywords from the job posting, achievements with numbers.",proTip:"Use the WorkAbroad Hub CV builder — it's pre-formatted for UAE, Saudi, UK, and Canada employers.",estimatedDuration:"2–3 days",category:"documents",ctaLink:"/services",ctaLabel:"Use our CV builder"},{key:"agency_vetting",title:"Vet any agency before paying",description:"Check the agency's NEA license is still valid (not expired), confirm they're physically located where they say, search for complaints. If they ask for KES 80,000+ upfront before showing you a contract, walk away.",proTip:"Use our NEA Agency Lookup to verify license status in 10 seconds.",estimatedDuration:"1 day",category:"agency",ctaLink:"/agencies",ctaLabel:"Verify an agency"}],o={AE:[{key:"english_test",title:"Take an English proficiency test (if required)",description:"Most UAE roles need IELTS, OET, or equivalent. Healthcare workers typically need IELTS 5.5+; construction and hospitality often accept basic English. Confirm with your recruiter.",estimatedDuration:"2–6 weeks (booking + result)",category:"skills"},{key:"medical_exam",title:"Complete the Gulf medical exam",description:"GCC-approved medical centres in Nairobi conduct the screening. HIV, Hep B/C, TB, pregnancy test (women), syphilis. Results valid 3 months.",estimatedDuration:"1 day for tests + 3–5 days for results",category:"documents"},{key:"visa_application",title:"Apply for the work visa via your sponsor",description:"Your UAE employer (sponsor) handles the visa — they apply through MoHRE. You provide passport, photos, attested certs. Entry permit arrives in 1–3 weeks.",estimatedDuration:"1–3 weeks",category:"application"},{key:"contract_review",title:"Read the contract carefully before signing",description:"Confirm: monthly salary, accommodation (provided or allowance?), food, transport, annual ticket home, end-of-service gratuity, working hours, off days. UAE law allows employer-paid one-way ticket every 2 years — make sure it's there.",proTip:"Pay our WhatsApp consultant to review the contract for KES 500 before you sign anything.",estimatedDuration:"1 day",category:"agency",ctaLink:"/services",ctaLabel:"Get contract reviewed"}],SA:[{key:"english_test",title:"English proficiency (if required)",description:"Skilled and healthcare roles need IELTS. Domestic and construction often only require basic conversational English.",estimatedDuration:"2–6 weeks",category:"skills"},{key:"medical_exam",title:"Saudi-approved medical exam",description:"GCC standard medical. The clinic must be on the Gulf-approved list — your agent will direct you to the right one.",estimatedDuration:"1 day + 3–5 days for results",category:"documents"},{key:"saudi_visa",title:"Saudi work visa + Musaned approval",description:"Domestic worker visas go through the Musaned platform. Skilled worker visas go through Qiwa. Your sponsor initiates — you provide passport + attested docs.",estimatedDuration:"2–4 weeks",category:"application"},{key:"contract_review",title:"Review the contract before signing",description:"Saudi contracts MUST specify salary in SAR, hours, off-days, accommodation. Domestic worker contracts have additional MoHRSD-specified clauses. Walk away from anything verbal.",proTip:"If you're going as a domestic worker, the contract must be in Arabic AND English with both signed.",estimatedDuration:"1 day",category:"agency"}],GB:[{key:"english_test",title:"Pass IELTS (or equivalent)",description:"UK Skilled Worker visa requires English at B1 level minimum. Healthcare and education roles often need higher (B2/C1).",estimatedDuration:"4–8 weeks",category:"skills"},{key:"uk_sponsor",title:"Get a UK employer sponsor + Certificate of Sponsorship (CoS)",description:"You can't apply for a Skilled Worker visa without a job offer from a licensed sponsor. NHS Trusts, care homes, hospitality chains. Once they issue your CoS, you have 3 months to apply for the visa.",estimatedDuration:"Highly variable — depends on job search",category:"application"},{key:"uk_visa",title:"Apply for the Skilled Worker visa",description:"Online application via gov.uk, biometrics at TLScontact Nairobi, IHS surcharge (~£1,035/year), visa fee (~£625 for 3 years). Decision in 3 weeks.",estimatedDuration:"3–6 weeks",category:"application"},{key:"tb_screening",title:"Complete TB screening",description:"Required for all visa applicants from Kenya (high TB burden country). Done at IOM Nairobi. Valid 6 months.",estimatedDuration:"1 day + 1 week for cert",category:"documents"}],CA:[{key:"english_test",title:"Take IELTS or CELPIP",description:"Express Entry and most work permit categories need English testing. Higher scores = more Express Entry points.",estimatedDuration:"4–8 weeks",category:"skills"},{key:"eca",title:"Get an Educational Credential Assessment (ECA)",description:"WES, IQAS, or ICAS evaluates your Kenyan qualifications against Canadian standards. Required for Express Entry. Takes 6–20 weeks.",estimatedDuration:"6–20 weeks",category:"documents"},{key:"lmia_or_pnp",title:"Find an LMIA-supported job OR get a Provincial Nomination",description:"Either: a Canadian employer gets a Labour Market Impact Assessment to hire you, OR a province nominates you under their PNP. Both unlock work permit eligibility.",estimatedDuration:"Highly variable",category:"application"},{key:"canada_visa",title:"Apply for the work permit + visitor visa",description:"Online via IRCC. Biometrics at VFS Nairobi. Medical exam at a panel physician. Processing 6–14 weeks.",estimatedDuration:"6–14 weeks",category:"application"}],QA:[{key:"medical_exam",title:"Gulf medical exam",description:"Same standard as UAE / Saudi. GCC-approved clinic in Nairobi.",estimatedDuration:"1 day + 3–5 days",category:"documents"},{key:"qatar_visa",title:"Qatari work visa via sponsor",description:"Employer applies for your visa through the MoI portal. You provide passport + attested certs + medical.",estimatedDuration:"2–4 weeks",category:"application"},{key:"qid_setup",title:"Plan QID + medical insurance on arrival",description:"Within 30 days of landing you must complete fingerprinting + medical to get your Qatar ID (QID). Without it you can't open a bank account or rent. Employer usually handles this.",estimatedDuration:"1 month after arrival",category:"departure"}],BH:[{key:"medical_exam",title:"Bahrain-approved medical exam",description:"Gulf-approved clinic, similar to UAE/Saudi requirements.",estimatedDuration:"1 day + results",category:"documents"},{key:"bahrain_visa",title:"Bahrain work visa",description:"Employer applies through LMRA. Processing 2–4 weeks. You provide passport + attested certs.",estimatedDuration:"2–4 weeks",category:"application"}],AU:[{key:"english_test",title:"Take IELTS (Academic preferred)",description:"Almost every Australian skilled visa requires English testing. Score thresholds vary by visa subclass.",estimatedDuration:"4–8 weeks",category:"skills"},{key:"skills_assessment",title:"Get a skills assessment from the relevant authority",description:"Engineers Australia for engineers, ACS for IT, ANMAC for nurses, etc. They verify your Kenyan qualifications match Australian standards.",estimatedDuration:"8–16 weeks",category:"skills"},{key:"visa_482_or_skilled",title:"Apply for the right visa subclass",description:"482 (Temporary Skill Shortage) needs an Australian employer sponsor. Subclass 189/190 (Skilled Independent/Nominated) use the points-based Express system.",estimatedDuration:"varies — 1 to 6 months",category:"application"}],DE:[{key:"german_language",title:"Learn German to A2 / B1",description:"EU Blue Card needs B1 for some sectors, A2 for others. Skilled trade visas often require B2. Goethe-Institut Nairobi runs courses.",estimatedDuration:"3–6 months of full-time study",category:"skills"},{key:"qualification_recognition",title:"Get your qualification officially recognised",description:"ZAB (Central Office for Foreign Education) confirms whether your Kenyan degree is equivalent to a German one. Required for EU Blue Card.",estimatedDuration:"3–4 months",category:"skills"},{key:"german_visa",title:"Apply for the EU Blue Card or Skilled Worker visa",description:"Online application + appointment at the German embassy in Nairobi. Job offer + minimum salary threshold required for Blue Card (€45,300/year as of 2026).",estimatedDuration:"2–4 months",category:"application"}],US:[{key:"english_test",title:"TOEFL or IELTS (if needed)",description:"Required for student visas and most professional categories. Employer sponsors may waive for fluent applicants.",estimatedDuration:"4–8 weeks",category:"skills"},{key:"us_visa_petition",title:"Get an approved US visa petition",description:"H-1B (specialty occupation, lottery-based, March), EB-3 (skilled worker, employer-sponsored, 6+ year wait for Kenyans), J-1 (training/exchange).",estimatedDuration:"varies wildly — 6 months to 6 years",category:"application"},{key:"us_interview",title:"Attend the embassy interview in Nairobi",description:"DS-160 online form, fee payment, interview slot booking. Bring petition approval (I-797), employer letter, DS-160 confirmation, passport.",estimatedDuration:"2–8 weeks after petition",category:"application"}]},r=[{key:"ticket_money",title:"Plan your money for travel and first month",description:"Even if your employer covers the air ticket, plan for: airport tax, first-week meals, transport from arrival airport, prepaid SIM, deposit for accommodation if you're paying. Most users budget KES 30,000–80,000.",proTip:"Carry enough cash for 7 days — don't rely on cards working immediately overseas.",estimatedDuration:"—",category:"financial"},{key:"family_setup",title:"Sort out NHIF, NSSF, and family arrangements",description:"Keep your NHIF and NSSF active (you can pay from abroad). Arrange how to send money home — M-Pesa Global, Wise, WorldRemit. Tell your family who their contact in Kenya is if you become unreachable.",estimatedDuration:"1 week",category:"financial"},{key:"embassy_register",title:"Register with the Kenyan embassy on arrival",description:"Most Kenyan embassies run a registration list of citizens in their country. Free, takes 10 minutes online or in person. They use it to reach you in case of emergency (war, evacuation, family death).",estimatedDuration:"1 day",category:"departure"},{key:"departure_prep",title:"Final week — what to pack and what to leave",description:"Carry: passport + visa printout, attested certs (originals + copies), 3 month's worth of any prescription meds, employer contract, KES 5,000 cash. Leave: anything you can't easily replace if luggage gets lost.",proTip:"Photograph every document and email yourself + a family member.",estimatedDuration:"1 week",category:"departure"}];function s(e){const t=(e||"").toUpperCase(),a=o[t]??[];return[...i,...a,...r]}const n=[{code:"AE",name:"UAE",flag:"🇦🇪"},{code:"SA",name:"Saudi Arabia",flag:"🇸🇦"},{code:"QA",name:"Qatar",flag:"🇶🇦"},{code:"BH",name:"Bahrain",flag:"🇧🇭"},{code:"GB",name:"United Kingdom",flag:"🇬🇧"},{code:"CA",name:"Canada",flag:"🇨🇦"},{code:"AU",name:"Australia",flag:"🇦🇺"},{code:"DE",name:"Germany",flag:"🇩🇪"},{code:"US",name:"USA",flag:"🇺🇸"}];export{n as S,s as g};
